#include <algorithm>
#include <vector>

int main() {
    std::vector<int> v = {1, 2, 3};
    // find: تبحث عن قيمة واحدة
    auto a = std::find(v.begin(), v.end(), 2);
    // find_first_of: تبحث عن أي تطابق من مجموعة
    std::vector<int> targets = {5, 3, 7};
    auto b = std::find_first_of(v.begin(), v.end(), targets.begin(), targets.end());
    return (*a) + (*b);
}
